def pairs(n):
    c = 0
    for i in range(n):
        for j in range(n):
            c += 1
    return c

# Merge sort: T(n) = 2T(n/2) + O(n) => O(n log n)
def mergesort(a):
    if len(a) <= 1: return a
    m = len(a)//2
    return merge(mergesort(a[:m]), mergesort(a[m:]))

def merge(u, v):
    i, j = 0, 0
    r = []
    while i < len(u) and j < len(v):
        if u[i] <= v[j]:
            r.append(u[i]); i += 1
        else:
            r.append(v[j]); j += 1
    return r + u[i:] + v[j:]

