def valid_paren(s):
    st=[]
    m={')':'(',']':'[','}':'{'}
    for ch in s:
        if ch in '([{': st.append(ch)
        elif ch in m:
            if not st or st.pop()!=m[ch]: return False
        else: return False
    return not st

