def quicksort(a):
    if len(a) <= 1: return a
    p = a[len(a)//2]
    return quicksort([x for x in a if x < p]) + [x for x in a if x==p] + quicksort([x for x in a if x > p])

def inorder(root):
    if not root: return []
    return inorder(root.left) + [root.val] + inorder(root.right)

# BST insert sketch
def insert(n, x):
    if n is None: return Node(x)
    if x < n.val: n.left = insert(n.left, x)
    else: n.right = insert(n.right, x)
    return n

def bfs(s, G):
    from collections import deque
    q=deque([s]); seen={s}
    while q:
        u=q.popleft()
        for v in G[u]:
            if v not in seen:
                seen.add(v); q.append(v)

